-- ═══════════════════════════════════════════════════════════════
-- 0035 · Wire technical specifications from official brand catalogues
--
-- Adds products.tech_specs (jsonb) and populates it for house wires from the
-- manufacturer catalogues (Polycab Mar-25, KEI 2024, RR Kabel, Havells): per
-- size the strand construction, insulation thickness, overall diameter, DC
-- conductor resistance, current-carrying capacity, plus per-line fire-test
-- results (oxygen index, temperature index, acid-gas, smoke density) with the
-- test method and specified value. Matched by brand + Quality grade + size.
-- Idempotent. Generated by scripts/gen_techspecs.py.
-- ═══════════════════════════════════════════════════════════════

alter table public.products add column if not exists tech_specs jsonb;
comment on column public.products.tech_specs is 'Structured technical data (conductor/insulation/dimensions/current-rating/fire-tests) from the manufacturer catalogue.';


update public.products set tech_specs = '{"line": "Conflame Green+", "insulation": {"material": "HR FR-LSH LF PVC", "thickness_mm": 0.6}, "conductor": {"material": "bright annealed electrolytic copper", "class": "5", "strands": "24/0.2", "resistance_ohm_km": 26.0}, "voltage_grade_v": 1100, "standards": ["IS 694:2010", "IS 8130"], "packing": "90 m coil, protective cartons", "colours": ["Red", "Yellow", "Blue", "Black", "Green", "Grey"], "source": "KEI House Wires Catalogue 2024", "max_operating_temp_c": 85, "fire_tests": [{"test": "Critical Oxygen Index", "method": "ASTM-D 2863", "value": "min 31%"}, {"test": "Temperature Index", "method": "ASTM-D 2863", "value": "min 250°C"}, {"test": "Acid Gas Generation", "method": "IEC 60754-1", "value": "max 20%"}, {"test": "Smoke Density Rating", "method": "ASTM-D 2843", "value": "max 60%"}], "dimensions": {"overall_diameter_mm": 2.8}, "current_rating_a": {"min": 9, "max": 10, "raw": [9, 10]}}'::jsonb
where brand = 'KEI' and category = 'Wires & Cables' and attrs->>'Quality' = 'HR FR-LSH'
  and split_part(attrs->>'Size', ' ', 1)::numeric = 0.75;

update public.products set tech_specs = '{"line": "Conflame Green+", "insulation": {"material": "HR FR-LSH LF PVC", "thickness_mm": 0.6}, "conductor": {"material": "bright annealed electrolytic copper", "class": "5", "strands": "32/0.2", "resistance_ohm_km": 19.5}, "voltage_grade_v": 1100, "standards": ["IS 694:2010", "IS 8130"], "packing": "90 m coil, protective cartons", "colours": ["Red", "Yellow", "Blue", "Black", "Green", "Grey"], "source": "KEI House Wires Catalogue 2024", "max_operating_temp_c": 85, "fire_tests": [{"test": "Critical Oxygen Index", "method": "ASTM-D 2863", "value": "min 31%"}, {"test": "Temperature Index", "method": "ASTM-D 2863", "value": "min 250°C"}, {"test": "Acid Gas Generation", "method": "IEC 60754-1", "value": "max 20%"}, {"test": "Smoke Density Rating", "method": "ASTM-D 2843", "value": "max 60%"}], "dimensions": {"overall_diameter_mm": 3.0}, "current_rating_a": {"min": 14, "max": 16, "raw": [14, 16]}}'::jsonb
